"""cycler — minimal shim for matplotlib's style-cycling helper.

Upstream cycler is a small standalone package that lets matplotlib /
seaborn build composable property cycles (``cycler('color', [...]) +
cycler('linestyle', [...])``). The plotly-backed matplotlib shim in
CodeBench never reads the actual cycle values, but several seaborn
modules do ``from cycler import cycler``/``Cycler`` at import time, so
the bare import has to succeed.

The classes here track the keys+values supplied so simple ``+`` /
``*`` / iteration works, which is enough for everything that lands in
``rcParams['axes.prop_cycle']`` to round-trip without an exception."""


from __future__ import annotations

from itertools import cycle as _cycle, product as _product
from typing import Any, Iterable


class Cycler:
    """A list-of-dicts wrapper that mimics the upstream API surface.

    The constructor accepts either a single ``(key, values)`` pair or
    a pre-built sequence of dicts (used by ``__add__`` / ``__mul__``).
    Iteration yields one dict per "step" of the cycle.
    """

    def __init__(self, key=None, values=None, _entries=None):
        if _entries is not None:
            self._entries = list(_entries)
            self.keys = set().union(*(d.keys() for d in self._entries)) if self._entries else set()
        else:
            self._entries = [{key: v} for v in (values or [])]
            self.keys = {key} if key is not None else set()

    def __iter__(self):
        return iter(dict(d) for d in self._entries)

    def __len__(self):
        return len(self._entries)

    def __add__(self, other):
        if not isinstance(other, Cycler):
            return NotImplemented
        if len(self) != len(other):
            raise ValueError("Can only add equal-length Cyclers")
        if self.keys & other.keys:
            raise ValueError("Cyclers must have disjoint keys to add")
        merged = [{**a, **b} for a, b in zip(self._entries, other._entries)]
        return Cycler(_entries=merged)

    def __mul__(self, other):
        if isinstance(other, int):
            return Cycler(_entries=self._entries * other)
        if isinstance(other, Cycler):
            if self.keys & other.keys:
                raise ValueError("Cyclers must have disjoint keys to multiply")
            merged = [{**a, **b} for a, b in _product(self._entries, other._entries)]
            return Cycler(_entries=merged)
        return NotImplemented

    __rmul__ = __mul__

    def __repr__(self):
        return f"Cycler({self._entries!r})"

    def by_key(self):
        """Return ``{key: [values...]}`` (upstream-compatible helper)."""
        out: dict[str, list[Any]] = {k: [] for k in self.keys}
        for d in self._entries:
            for k in self.keys:
                out[k].append(d.get(k))
        return out


def cycler(*args, **kwargs):
    """Build a :class:`Cycler` from ``cycler('color', [...])`` or
    ``cycler(color=[...])`` style calls.

    Supports the common signatures used by matplotlib and seaborn:
      - ``cycler(key, values)``
      - ``cycler(label=values, ...)``  (multi-key keyword form)
      - ``cycler(some_cycler)``  (pass-through)"""
    if len(args) == 1 and isinstance(args[0], Cycler) and not kwargs:
        return args[0]
    if len(args) == 2 and not kwargs:
        return Cycler(args[0], args[1])
    if not args:
        # cycler(color=[...]) — produce one cycler per kwarg, combined via +
        result = None
        for k, v in kwargs.items():
            c = Cycler(k, list(v))
            result = c if result is None else result + c
        if result is None:
            raise TypeError("cycler() needs at least one argument")
        return result
    raise TypeError(f"cycler(): unsupported signature args={args!r} kwargs={kwargs!r}")


__all__ = ['Cycler', 'cycler']
__version__ = '0.12.1-codebench-shim'
